import json
import hmac
import hashlib
import os
import boto3
from datetime import datetime
from botocore.exceptions import ClientError

# Initialize AWS clients with least privilege
dynamodb = boto3.resource('dynamodb')
secrets_client = boto3.client('secretsmanager')

# Environment variables
TABLE_NAME = os.environ.get('DYNAMODB_TABLE')
SECRET_NAME = os.environ.get('WEBHOOK_SECRET_NAME')
ALLOWED_PARTNERS = os.environ.get('ALLOWED_PARTNERS', '').split(',')
MAX_PAYLOAD_SIZE = int(os.environ.get('MAX_PAYLOAD_SIZE', 1048576))  # 1MB default

def get_webhook_secret():
    """Retrieve webhook secret from AWS Secrets Manager"""
    try:
        response = secrets_client.get_secret_value(SecretId=SECRET_NAME)
        return response['SecretString']
    except ClientError as e:
        print(f"Error retrieving secret: {e}")
        raise

def verify_signature(payload, signature, secret):
    """Verify HMAC signature of webhook payload"""
    if not signature:
        return False
    
    expected_signature = hmac.new(
        secret.encode('utf-8'),
        payload.encode('utf-8'),
        hashlib.sha256
    ).hexdigest()
    
    return hmac.compare_digest(signature, expected_signature)

def validate_event_structure(event_data):
    """Validate event structure against allowlist schema"""
    required_fields = ['partner_id', 'event_type', 'timestamp', 'user_action']
    allowed_event_types = ['user_login', 'user_logout', 'profile_update', 'purchase']
    
    # Check required fields
    for field in required_fields:
        if field not in event_data:
            return False, f"Missing required field: {field}"
    
    # Validate partner_id against allowlist
    if event_data['partner_id'] not in ALLOWED_PARTNERS:
        return False, "Invalid partner_id"
    
    # Validate event_type against allowlist
    if event_data['event_type'] not in allowed_event_types:
        return False, "Invalid event_type"
    
    # Validate timestamp format
    try:
        datetime.fromisoformat(event_data['timestamp'].replace('Z', '+00:00'))
    except (ValueError, AttributeError):
        return False, "Invalid timestamp format"
    
    # Validate user_action structure
    if not isinstance(event_data['user_action'], dict):
        return False, "user_action must be a dictionary"
    
    # Sanitize string fields to prevent injection
    for key, value in event_data.items():
        if isinstance(value, str):
            if len(value) > 10000:  # Limit string length
                return False, f"Field {key} exceeds maximum length"
    
    return True, None

def sanitize_data(data):
    """Sanitize data for safe processing - use JSON instead of pickle"""
    # Never use pickle for untrusted data - use JSON for safe serialization
    if isinstance(data, dict):
        sanitized = {}
        for key, value in data.items():
            # Only allow alphanumeric keys with underscores
            if isinstance(key, str) and key.replace('_', '').isalnum():
                if isinstance(value, (str, int, float, bool, type(None))):
                    sanitized[key] = value
                elif isinstance(value, dict):
                    sanitized[key] = sanitize_data(value)
                elif isinstance(value, list):
                    sanitized[key] = [sanitize_data(item) if isinstance(item, dict) else item 
                                     for item in value if isinstance(item, (str, int, float, bool, dict))]
        return sanitized
    return data

def process_user_action(event_data):
    """Process validated user action"""
    # Sanitize the entire event data
    sanitized_event = sanitize_data(event_data)
    
    # Store in DynamoDB with sanitized data
    table = dynamodb.Table(TABLE_NAME)
    
    item = {
        'event_id': f"{sanitized_event['partner_id']}#{sanitized_event['timestamp']}",
        'partner_id': sanitized_event['partner_id'],
        'event_type': sanitized_event['event_type'],
        'timestamp': sanitized_event['timestamp'],
        'user_action': json.dumps(sanitized_event['user_action']),  # Store as JSON string
        'processed_at': datetime.utcnow().isoformat()
    }
    
    table.put_item(Item=item)
    return item

def lambda_handler(event, context):
    """Main Lambda handler for webhook events"""
    
    try:
        # Validate request method
        if event.get('httpMethod') != 'POST':
            return {
                'statusCode': 405,
                'body': json.dumps({'error': 'Method not allowed'})
            }
        
        # Check payload size
        body = event.get('body', '')
        if len(body) > MAX_PAYLOAD_SIZE:
            return {
                'statusCode': 413,
                'body': json.dumps({'error': 'Payload too large'})
            }
        
        # Get signature from headers
        headers = event.get('headers', {})
        signature = headers.get('X-Webhook-Signature') or headers.get('x-webhook-signature')
        
        # Retrieve webhook secret
        webhook_secret = get_webhook_secret()
        
        # Verify signature
        if not verify_signature(body, signature, webhook_secret):
            return {
                'statusCode': 401,
                'body': json.dumps({'error': 'Invalid signature'})
            }
        
        # Parse JSON payload (safe deserialization)
        try:
            event_data = json.loads(body)
        except json.JSONDecodeError:
            return {
                'statusCode': 400,
                'body': json.dumps({'error': 'Invalid JSON payload'})
            }
        
        # Validate event structure
        is_valid, error_message = validate_event_structure(event_data)
        if not is_valid:
            return {
                'statusCode': 400,
                'body': json.dumps({'error': error_message})
            }
        
        # Process the validated event
        result = process_user_action(event_data)
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Event processed successfully',
                'event_id': result['event_id']
            })
        }
        
    except Exception as e:
        # Log error without exposing sensitive details
        print(f"Error processing webhook: {type(e).__name__}")
        return {
            'statusCode': 500,
            'body': json.dumps({'error': 'Internal server error'})
        }